# Volumetric Beams

A React Three Fiber full-screen shader that raymarches volumetric light beams using Henyey-Greenstein scattering and angular star patterns. The camera orbits automatically and responds to mouse movement. Highly configurable via props for beam count, density, color, ribbing, and post-processing.

## Use when
- Building a dark, futuristic SaaS or tech product landing page with a dramatic light-beam background.
- Creating an interactive art direction piece where cursor movement controls the volumetric camera.
- Showcasing a premium brand with a cinematic raymarched shader background.
- Adding a high-performance WebGL shader effect without raw WebGL setup.

## Stack
- Framework: react
- Libraries: three, @react-three/fiber
- Requires: tailwind, shadcn

## Install
```bash
three @react-three/fiber
```

## Component — volumetric-beams.tsx
```tsx
import React, { useMemo, useRef, useEffect } from 'react'
import * as THREE from 'three'
import { Canvas, useFrame, useThree } from '@react-three/fiber'

const vertexShader = `
  varying vec2 vUv;
  void main() {
    vUv = uv;
    gl_Position = vec4(position.xy, 0.0, 1.0);
  }
`

const fragmentShader = `
  precision highp float;
  varying vec2 vUv;
  uniform float uTime;
  uniform vec2 uResolution;
  uniform vec2 uMouse;
  uniform float uSpeed;
  uniform float uRadius;
  uniform float uFov;
  uniform float uMouseInfluence;
  uniform float uAutoRotateSpeed;
  uniform float uBeamCount;
  uniform float uHalfAngle;
  uniform float uEdgeSoft;
  uniform float uBeamRot;
  uniform float uTwistDepth;
  uniform float uDensity;
  uniform float uFalloff;
  uniform float uAniso;
  uniform float uLightIntensity;
  uniform vec3 uLightColor;
  uniform vec3 uTint;
  uniform float uStripeFreq;
  uniform float uStripeAmp;
  uniform float uStripeSharp;
  uniform float uStripeSpeed;
  uniform float uStripeJit;
  uniform float uVolSteps;
  uniform float uStepMin;
  uniform float uStepMax;
  uniform float uMaxDist;
  uniform float uExposure;
  uniform float uGamma;
  uniform float uGrainAmount;
  uniform float uVignette;
  uniform vec3 uBgColor;

  const float PI = 3.141592653589793;
  float hash21(vec2 p){p=fract(p*vec2(123.34,345.45));p+=dot(p,p+34.45);return fract(p.x*p.y);}
  mat2 rot2(float a){float s=sin(a),c=cos(a);return mat2(c,-s,s,c);}

  void beamAxis(vec2 p,float N,float rot,out vec2 axis,out float angDist){
    float ang=atan(p.y,p.x)+rot;
    float period=2.0*PI/max(1.0,N);
    float k=floor(ang/period+0.5);
    float centerAng=k*period;
    axis=vec2(cos(centerAng-rot),sin(centerAng-rot));
    float d=ang-centerAng;
    d=mod(d+PI,2.0*PI)-PI;
    angDist=abs(d);
  }

  float beamMask(float ad,float halfAng,float edgeSoft){
    return 1.0-smoothstep(max(0.0,halfAng-edgeSoft),halfAng+edgeSoft,ad);
  }

  float hg(float mu,float g){
    float g2=g*g;
    return(1.0-g2)/pow(1.0+g2-2.0*g*mu,1.5);
  }

  float mediumDensity(vec3 p,float t,out vec2 si){
    vec3 q=p;
    q.xy*=rot2(uTwistDepth*q.z);
    vec2 axis;float ad;
    beamAxis(q.xy,uBeamCount,uBeamRot,axis,ad);
    float beam=beamMask(ad,uHalfAngle,uEdgeSoft);
    float r=length(q.xy);
    float center=exp(-uFalloff*r*r);
    vec2 perp=vec2(-axis.y,axis.x);
    float coord=dot(q.xy,perp);
    float jit=uStripeJit*sin(0.7*q.z+2.3*coord+1.7*t);
    float stripes=0.5+0.5*sin(coord*uStripeFreq+jit-t*uStripeSpeed);
    stripes=pow(clamp(stripes,0.0,1.0),uStripeSharp);
    si=vec2(stripes,beam);
    return uDensity*beam*center;
  }

  void main(){
    float t=uTime*uSpeed;
    vec2 uv=(gl_FragCoord.xy-0.5*uResolution.xy)/uResolution.y;
    float az=t*uAutoRotateSpeed+(uMouse.x*2.0-1.0)*PI*0.35*uMouseInfluence;
    float el=(uMouse.y*2.0-1.0)*0.25*uMouseInfluence;
    vec3 ro=vec3(cos(az)*cos(el),sin(el),sin(az)*cos(el))*uRadius;
    vec3 ww=normalize(-ro);
    vec3 uu=normalize(cross(vec3(0,1,0),ww));
    vec3 vv=cross(ww,uu);
    vec3 rd=normalize(uv.x*uu+uv.y*vv+uFov*ww);
    vec3 col=uBgColor;
    vec3 accum=vec3(0);
    float Tr=1.0;
    float dist=0.0;
    int stepsHard=int(uVolSteps);
    for(int i=0;i<256;i++){
      if(i>=stepsHard)break;
      float s=mix(uStepMin,uStepMax,clamp(dist/uMaxDist,0.0,1.0));
      vec3 pos=ro+rd*dist;
      vec2 si;
      float dens=mediumDensity(pos,t,si);
      vec3 L=normalize(-pos);
      float mu=dot(rd,L);
      float phase=hg(mu,uAniso);
      accum+=Tr*uLightColor*uLightIntensity*phase*dens*s;
      Tr*=exp(-dens*s);
      dist+=s;
      if(Tr<1e-3||dist>uMaxDist)break;
    }
    col+=accum*abs(ro*0.3)*uTint;
    col*=clamp(1.0-uVignette*length(uv),0.0,1.0);
    float g=(hash21(gl_FragCoord.xy+fract(t*123.45))-0.5)*uGrainAmount*1.4;
    col+=g;
    col*=uExposure;
    col=col/(1.0+col);
    col=pow(col,vec3(1.0/uGamma));
    gl_FragColor=vec4(col,1.0);
  }
`

function VolumetricBeamsShader({
  speed = 0.25, autoRotateSpeed = 0.015, mouseInfluence = 0.45,
  cameraRadius = 3.8, fov = 1.65,
  beamCount = 4, beamHalfAngle = 0.085, beamEdgeSoft = 0.045, beamRotation = 0.0, twistDepth = 0.06,
  density = 1.15, falloff = 0.55, anisotropy = 0.76, lightIntensity = 2.2,
  lightColor = [0.64, 0.74, 1.0], tint = [0.55, 0.58, 0.95],
  stripeFreq = 42.0, stripeAmp = 0.55, stripeSharp = 1.85, stripeSpeed = 0.12, stripeJitter = 0.25,
  volSteps = 110, stepMin = 0.015, stepMax = 0.06, maxDist = 18.0,
  exposure = 1.05, gamma = 2.0, grainAmount = 0.045, vignette = 0.35, bgColor = [0.04, 0.035, 0.06],
  pointerSmoothing = 0.18,
  ...meshProps
}: any) {
  const mat = useRef(null)
  const { size, gl, pointer } = useThree()
  const tmpV2 = useMemo(() => new THREE.Vector2(), [])
  const uniforms = useMemo(() => ({
    uTime:{value:0},uResolution:{value:new THREE.Vector2(1,1)},uMouse:{value:new THREE.Vector2(0.5,0.5)},
    uSpeed:{value:speed},uRadius:{value:cameraRadius},uFov:{value:fov},uMouseInfluence:{value:mouseInfluence},uAutoRotateSpeed:{value:autoRotateSpeed},
    uBeamCount:{value:beamCount},uHalfAngle:{value:beamHalfAngle},uEdgeSoft:{value:beamEdgeSoft},uBeamRot:{value:beamRotation},uTwistDepth:{value:twistDepth},
    uDensity:{value:density},uFalloff:{value:falloff},uAniso:{value:anisotropy},uLightIntensity:{value:lightIntensity},
    uLightColor:{value:new THREE.Vector3().fromArray(lightColor)},uTint:{value:new THREE.Vector3().fromArray(tint)},
    uStripeFreq:{value:stripeFreq},uStripeAmp:{value:stripeAmp},uStripeSharp:{value:stripeSharp},uStripeSpeed:{value:stripeSpeed},uStripeJit:{value:stripeJitter},
    uVolSteps:{value:volSteps},uStepMin:{value:stepMin},uStepMax:{value:stepMax},uMaxDist:{value:maxDist},
    uExposure:{value:exposure},uGamma:{value:gamma},uGrainAmount:{value:grainAmount},uVignette:{value:vignette},
    uBgColor:{value:new THREE.Vector3().fromArray(bgColor)},
  }), [])

  useFrame((state) => {
    const dpr = gl.getPixelRatio()
    uniforms.uTime.value = state.clock.elapsedTime
    uniforms.uResolution.value.set(size.width * dpr, size.height * dpr)
    const mx = 0.5 + state.pointer.x * 0.5; const my = 0.5 + state.pointer.y * 0.5
    uniforms.uMouse.value.lerp(tmpV2.set(mx, my), pointerSmoothing)
  })

  return (
    <mesh frustumCulled={false} {...meshProps}>
      <planeGeometry args={[2, 2, 1, 1]} />
      <shaderMaterial vertexShader={vertexShader} fragmentShader={fragmentShader} uniforms={uniforms} depthTest={false} depthWrite={false} side={THREE.DoubleSide} />
    </mesh>
  )
}

export default function VolumetricBeamsFullScreen({
  dpr = [1, 2],
  gl = { antialias: true },
  className = 'fixed inset-0 bg-black',
  title = 'Background Shader',
  subtitle = 'volumetric Beams',
  headingClassName = '',
  subtitleClassName = '',
  ...shaderProps
}: any) {
  return (
    <div className={className}>
      <Canvas dpr={dpr} gl={gl} className="w-full h-full touch-none">
        <VolumetricBeamsShader {...shaderProps} />
      </Canvas>
      <div className="pointer-events-none absolute inset-x-0 top-4 sm:top-6 md:top-80 z-10 flex justify-center">
        <div className="text-center">
          <h1 className={`select-none font-extrabold uppercase tracking-[0.25em] text-2xl sm:text-3xl md:text-5xl bg-gradient-to-r from-indigo-200/90 via-blue-300 to-indigo-200/90 bg-clip-text text-transparent drop-shadow-[0_8px_32px_rgba(64,128,255,0.35)] ${headingClassName}`}>
            {title}
          </h1>
          {subtitle && <p className={`mt-2 text-xs sm:text-sm md:text-base tracking-widest text-slate-200/70 ${subtitleClassName}`}>{subtitle}</p>}
        </div>
      </div>
    </div>
  )
}

export { VolumetricBeamsShader }
```

